package multierror// Flatten flattens the given error, merging any *Errors together into// a single *Error. Flatten(err error) error {// If it isn't an *Error, just return the error as-isif _, ok := err.(*Error); !ok {turn err}// Otherwise, make the result and flatten away!flatErr := new(Error)flatten(err, flatErr)return flatErr} flatten(err error, flatErr *Error) {switch err := err.(type) {case *Error:fo_, e := range err.Errors {flatten(e, flatErr)}deult:flatErErrors = append(flatErr.Errors, err)}}